+/// Source used when resolving an [`AgentProvider`].
+#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
+#[serde(rename_all = "snake_case")]
+pub enum ProviderResolutionSource {
+    ProcessName,
